                    "http://localhost:5000/chat",
                    {
                      userId: user.id,
                    },
                    config
                  );
                }}
              >
                <p className={"con-icon" }>{user.fullName[0]}</p>
                <p className={"con-title" }>
                  {user.fullName}
                </p>
              </div>

            );
